/* ---------- Загрузка ---------- */
async function loadCatalog(){
  if (location.protocol === 'file:') {
    ALL = PRODUCTS_INLINE;
  } else {
    try{
      const res = await fetch('data/products.json', { cache:'no-store' });
      if (!res.ok) throw new Error();
      ALL = await res.json();
    } catch(e){
      ALL = PRODUCTS_INLINE;
    }
  }
  applyUrlParams();
  buildBrandList();
  render();
}

function applyUrlParams(){
  const p = new URLSearchParams(location.search);
  const type   = p.get('type');
  const gender = p.get('gender');
  const brand  = p.get('brand');
  const q      = p.get('q');

  if (type === 'original') document.getElementById('f-original').checked = true;
  if (type === 'oil')      document.getElementById('f-oil').checked = true;
  if (gender === 'men' || gender === 'male')   document.getElementById('f-male').checked = true;
  if (gender === 'women' || gender === 'female') document.getElementById('f-female').checked = true;
  if (gender === 'unisex') document.getElementById('f-unisex').checked = true;
  if (brand) { activeBrand = brand; }
  if (q) { const inp = document.getElementById('sb-search-input'); if(inp) inp.value = q; }
}

/* ---------- Список брендов в сайдбаре ---------- */
function buildBrandList(){
  const counts = {};
  ALL.forEach(p => { counts[p.brand] = (counts[p.brand] || 0) + 1; });
  const brands = Object.entries(counts).sort((a,b) => a[0].localeCompare(b[0], 'ru'));

  const ul = document.getElementById('brand-list');
  if (!ul) return;

  function renderBrands(){
    const visible = brandsExpanded ? brands : brands.slice(0, BRANDS_VISIBLE);
    ul.innerHTML = `
      <li>
        <a href="#" class="${activeBrand==='all'?'active':''}" onclick="setBrand('all',event)">
          <span>Все бренды</span>
          <span class="count">${ALL.length}</span>
        </a>
      </li>
      ${visible.map(([b,c]) => `
        <li>
          <a href="#" class="${activeBrand===b?'active':''}" onclick="setBrand('${CSS.escape ? b.replace(/'/g,"\\'") : b}',event)" data-brand="${b}">
            <span>${b}</span>
            <span class="count">${c}</span>
          </a>
        </li>`).join('')}`;

    const btn = document.getElementById('brand-show-more');
    const lbl = document.getElementById('brand-more-label');
    if (brands.length <= BRANDS_VISIBLE){ btn.style.display = 'none'; return; }
    btn.style.display = '';
    if (brandsExpanded){
      lbl.textContent = 'Свернуть';
      btn.querySelector('svg').style.transform = 'rotate(180deg)';
    } else {
      lbl.textContent = `+${brands.length - BRANDS_VISIBLE} брендов`;
      btn.querySelector('svg').style.transform = '';
    }
  }

  renderBrands();
  window._renderBrands = renderBrands;
}

function setBrand(brand, e){
  if (e) e.preventDefault();
  activeBrand = brand;
  if (window._renderBrands) window._renderBrands();
  updateBreadcrumb();
  render();
}

function toggleMoreBrands(){
  brandsExpanded = !brandsExpanded;
  if (window._renderBrands) window._renderBrands();
}

function toggleSidebar(){
  document.getElementById('sidebar')?.classList.toggle('hidden-mobile');
}

function updateBreadcrumb(){
  const el = document.getElementById('bc-current');
  if (!el) return;
  el.textContent = activeBrand === 'all' ? 'Весь каталог' : activeBrand;
}

/* ---------- Фильтрация ---------- */
function getFilters(){
  return {
    original: document.getElementById('f-original')?.checked,
    oil:      document.getElementById('f-oil')?.checked,
    male:     document.getElementById('f-male')?.checked,
    female:   document.getElementById('f-female')?.checked,
    unisex:   document.getElementById('f-unisex')?.checked,
    instock:  document.getElementById('f-instock')?.checked,
    q:        (document.getElementById('sb-search-input')?.value || '').trim().toLowerCase(),
    sort:     document.getElementById('sort-select')?.value || 'default',
  };
}

function applyFilters(){ render(); }

function filtered(){
  const f = getFilters();
  const typeActive = f.original || f.oil;
  const genderActive = f.male || f.female || f.unisex;

  let list = ALL.filter(p => {
    if (activeBrand !== 'all' && p.brand !== activeBrand) return false;
    if (typeActive){
      if (f.original && !f.oil && p.type !== 'original') return false;
      if (f.oil && !f.original && p.type !== 'oil') return false;
    }
    if (genderActive){
      const ok = (f.male && p.gender==='male') || (f.female && p.gender==='female') || (f.unisex && p.gender==='unisex');
      if (!ok) return false;
    }
    if (f.instock && !p.in_stock) return false;
    if (f.q){
      const hay = (p.name + ' ' + p.brand).toLowerCase();
      if (!hay.includes(f.q)) return false;
    }
    return true;
  });

  const sort = f.sort;
  if (sort === 'az')         list.sort((a,b) => a.name.localeCompare(b.name,'ru'));
  if (sort === 'za')         list.sort((a,b) => b.name.localeCompare(a.name,'ru'));
  if (sort === 'price-asc')  list.sort((a,b) => priceFrom(a) - priceFrom(b));
  if (sort === 'price-desc') list.sort((a,b) => priceFrom(b) - priceFrom(a));
  if (sort === 'new')        list.sort((a,b) => (b.badge==='new') - (a.badge==='new'));
  return list;
}

/* ---------- Карточка ---------- */
function priceHtml(price){
  const rub = Math.floor(price);
  const kop = Math.round((price - rub) * 100);
  const fmt = new Intl.NumberFormat('ru-RU').format(rub);
  return `${fmt}<sup>${String(kop).padStart(2,'0')}</sup> ₽`;
}

function starsHtml(rating){
  const filled = Math.round(rating || 0);
  return Array.from({length:5}, (_,i) =>
    `<svg class="star${i < filled?' filled':''}" viewBox="0 0 24 24"><path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/></svg>`
  ).join('');
}

function cardHtml(p){
  const img = p.image_url || 'images/placeholder.svg';
  const price = priceFrom(p);
  const multi = p.variants.length > 1;

  const badge = p.badge === 'hit' ? `<div class="pcard-badge">Хит</div>`
              : p.badge === 'new' ? `<div class="pcard-badge new">Новинка</div>` : '';

  const stockBadge = p.in_stock
    ? `<div class="stock-badge in"><div class="stock-dot"></div>В наличии</div>`
    : `<div class="stock-badge out"><div class="stock-dot"></div>Нет в наличии</div>`;

  const cartBtnHtml = p.in_stock
    ? `<button class="cart-btn" onclick="quickAdd(event,'${p.id}')" title="В корзину">
         <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8">
           <path d="M6 6h15l-1.5 9h-12z"/><circle cx="9" cy="20" r="1.3"/><circle cx="18" cy="20" r="1.3"/><path d="M6 6 5 3H2"/>
         </svg>
       </button>`
    : `<button class="cart-btn out-btn" disabled title="Нет в наличии">
         <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8">
           <path d="M6 6h15l-1.5 9h-12z"/><circle cx="9" cy="20" r="1.3"/><circle cx="18" cy="20" r="1.3"/><path d="M6 6 5 3H2"/>
         </svg>
       </button>`;

  return `
  <article class="pcard" onclick="location.href='product.html?id=${p.id}'" style="cursor:pointer">
    <div class="pcard-img-wrap">
      ${badge}
      <img src="${img}" alt="${p.brand} ${p.name}" class="pcard-img" loading="lazy"
           onerror="this.src='images/placeholder.svg'">
    </div>
    <div class="pcard-body">
      <div class="pcard-brand">${p.brand}</div>
      <div class="pcard-name">${p.name}</div>
      <div class="pcard-rating">
        <div class="stars">${starsHtml(0)}</div>
        <span class="rating-val">0.0</span>
      </div>
      ${stockBadge}
      <div class="pcard-footer">
        <div>
          <div class="pcard-price">${multi?'от ':''} ${priceHtml(price)}</div>
          <div class="pcard-price-note">${p.type==='oil'?'масляная · ':''}${genderLabel(p.gender)}</div>
        </div>
        ${cartBtnHtml}
      </div>
    </div>
  </article>`;
}

/* ---------- Рендер ---------- */
function render(){
  const list = filtered();
  const grid = document.getElementById('cat-grid');
  const noRes = document.getElementById('no-results');
  const count = document.getElementById('cat-count');

  if (count) count.textContent = `${list.length} ${plural(list.length,'товар','товара','товаров')}`;

  if (!list.length){
    grid.innerHTML = '';
    noRes?.classList.remove('hidden');
    return;
  }
  noRes?.classList.add('hidden');
  grid.innerHTML = list.map(cardHtml).join('');
}

/* ---------- Быстрое добавление в корзину ---------- */
function quickAdd(e, id){
  e.stopPropagation();
  const p = ALL.find(x => x.id === id);
  if (!p || !p.in_stock) return;
  const v = p.variants[0];
  addToCart({ id:p.id, name:p.name, brand:p.brand, type:p.type, volume:v.volume, price:v.price });
}

/* ---------- Переключение вида ---------- */
function setView(mode, btn){
  const grid = document.getElementById('cat-grid');
  grid.classList.remove('view-list','view-2');
  document.querySelectorAll('.view-btn').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  if (mode === 'list')  grid.classList.add('view-list');
  if (mode === 'grid2') grid.classList.add('view-2');
}

/* ---------- Поиск в сайдбаре ---------- */
document.addEventListener('DOMContentLoaded', () => {
  document.getElementById('sb-search-input')?.addEventListener('input', () => render());
});

/* ---------- Помощники ---------- */
function plural(n, one, few, many){
  const m10 = n % 10, m100 = n % 100;
  if (m10 === 1 && m100 !== 11) return one;
  if (m10 >= 2 && m10 <= 4 && (m100 < 10 || m100 >= 20)) return few;
  return many;
}

/* ---------- Модалка товара ---------- */
let currentProduct = null, currentVariant = 0;

function openProduct(id){
  const p = ALL.find(x => x.id === id); if (!p) return;
  currentProduct = p; currentVariant = 0;
  const img = p.image_url || 'images/placeholder.svg';
  const variants = p.variants.map((v,i) =>
    `<button data-var="${i}" onclick="selectVariant(${i})" class="chip ${i===0?'active':''}">${v.volume}</button>`).join('');

  document.getElementById('modal-box').innerHTML = `
    <div class="grid md:grid-cols-2">
      <img src="${img}" alt="${p.brand} ${p.name}" class="w-full aspect-square object-cover" style="background:var(--bg)">
      <div class="p-6 md:p-8 flex flex-col">
        <div class="flex items-start justify-between">
          <div class="text-xs tracking-luxe" style="color:var(--muted)">${p.brand}</div>
          <button onclick="closeProduct()" class="text-gold text-2xl leading-none">×</button>
        </div>
        <h2 class="font-serif text-3xl mt-1">${p.name}</h2>
        <div class="text-sm mt-2" style="color:var(--muted)">
          ${p.type==='oil'?'Масляная · ':''}${genderLabel(p.gender)}
          ${p.in_stock ? ' · <span style="color:#4caf72">В наличии</span>' : ' · <span style="color:#c98">Нет в наличии</span>'}
        </div>
        <p class="text-sm mt-4 leading-relaxed">${p.description||''}</p>
        <div class="mt-4 text-sm leading-relaxed hairline-t pt-4" style="color:var(--muted)">
          <span class="text-gold">Ноты:</span> ${p.notes||'—'}
        </div>
        <div class="mt-5">
          <div class="text-xs tracking-luxe mb-2" style="color:var(--muted)">ОБЪЁМ</div>
          <div class="flex flex-wrap gap-2">${variants}</div>
        </div>
        <div class="mt-5 flex items-end justify-between">
          <div>
            <div id="pv-price" class="text-gold text-2xl font-serif">${money(p.variants[0].price)}</div>
            <div id="pv-whole" class="text-xs" style="color:var(--muted)">опт ${money(p.variants[0].price_wholesale ?? p.variants[0].price)}</div>
          </div>
        </div>
        <button onclick="addCurrentToCart()" class="btn btn-solid w-full mt-6"
          ${p.in_stock ? '' : 'disabled style="opacity:.4;cursor:not-allowed"'}>
          ${p.in_stock ? 'В корзину' : 'Нет в наличии'}
        </button>
      </div>
    </div>`;
  document.getElementById('product-modal').classList.add('open');
}

function selectVariant(i){
  currentVariant = i;
  const v = currentProduct.variants[i];
  document.getElementById('pv-price').textContent = money(v.price);
  document.getElementById('pv-whole').textContent = 'опт ' + money(v.price_wholesale ?? v.price);
  document.querySelectorAll('[data-var]').forEach(b => b.classList.toggle('active', +b.dataset.var === i));
}

function addCurrentToCart(){
  if (!currentProduct || !currentProduct.in_stock) return;
  const v = currentProduct.variants[currentVariant];
  addToCart({ id:currentProduct.id, name:currentProduct.name, brand:currentProduct.brand,
              type:currentProduct.type, volume:v.volume, price:v.price });
  closeProduct();
}

function closeProduct(){ document.getElementById('product-modal').classList.remove('open'); }

document.addEventListener('DOMContentLoaded', loadCatalog);
